 31→public class SpacingAroundColonRule : StandardRule("colon-spacing") {
 32→    override fun beforeVisitChildNodes(
 33→        node: ASTNode,
 34→        autoCorrect: Boolean,
 35→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 36→    ) {
 37→        if (node.elementType == COLON) {
 38→            val psiParent = node.psi.parent
 39→            if (node.isPartOf(ANNOTATION) || node.isPartOf(ANNOTATION_ENTRY)) {
 40→                // TODO: https://github.com/pinterest/ktlint/issues/2093 Enforce no spacing
 41→                return
 42→            }
 43→            val prevLeaf = node.prevLeaf()
 44→            if (prevLeaf != null && prevLeaf.isWhiteSpaceWithNewline()) {
 45→                emit(prevLeaf.startOffset, "Unexpected newline before \":\"", true)
 46→                if (autoCorrect) {
 47→                    val prevNonCodeElements =
 48→                        node
 49→                            .siblings(forward = false)
 50→                            .takeWhile { it.isWhiteSpace() || it.isPartOfComment() }
 51→                            .toList()
 52→                            .reversed()
 53→                    when {
 54→                        psiParent is KtProperty || psiParent is KtNamedFunction -> {
 55→                            val equalsSignElement =
 56→                                node
 57→                                    .siblings(forward = true)
 58→                                    .firstOrNull { it.elementType == EQ }
 59→                            if (equalsSignElement != null) {
 60→                                equalsSignElement
 61→                                    .treeNext
 62→                                    ?.let { treeNext ->
 63→                                        prevNonCodeElements.forEach {
 64→                                            node.treeParent.addChild(it, treeNext)
 65→                                        }
 66→                                        if (treeNext.isWhiteSpace()) {
 67→                                            equalsSignElement.treeParent.removeChild(treeNext)
 68→                                        }
 69→                                        Unit
 70→                                    }
 71→                            }
 72→                            val blockElement =
 73→                                node
 74→                                    .siblings(forward = true)
 75→                                    .firstIsInstanceOrNull<KtBlockExpression>()
 76→                            if (blockElement != null) {
 77→                                val before =
 78→                                    blockElement
 79→                                        .firstChildNode
 80→                                        .nextSibling()
 81→                                prevNonCodeElements
 82→                                    .let {
 83→                                        if (it.first().isWhiteSpace()) {
 84→                                            blockElement.treeParent.removeChild(it.first())
 85→                                            it.drop(1)
 86→                                        }
 87→                                        if (it.last().isWhiteSpaceWithNewline()) {
 88→                                            blockElement.treeParent.removeChild(it.last())
 89→                                            it.dropLast(1)
 90→                                        } else {
 91→                                            it
 92→                                        }
 93→                                    }.forEach {
 94→                                        blockElement.addChild(it, before)
 95→                                    }
 96→                            }
 97→                        }
 98→                        prevLeaf.prevLeaf()?.isPartOfComment() == true -> {
 99→                            val nextLeaf = node.nextLeaf()
100→                            prevNonCodeElements.forEach {
101→                                node.treeParent.addChild(it, nextLeaf)
102→                            }
103→                            if (nextLeaf != null && nextLeaf.isWhiteSpace()) {
104→                                node.treeParent.removeChild(nextLeaf)
105→                            }
106→                        }
107→                        else -> {
108→                            val text = prevLeaf.text
109→                            if (node.removeSpacingBefore) {
110→                                prevLeaf.treeParent.removeChild(prevLeaf)
111→                            } else {
112→                                (prevLeaf as LeafPsiElement).rawReplaceWithText(" ")
113→                            }
114→                            node.upsertWhitespaceAfterMe(text)
115→                        }
116→                    }
117→                }
118→            }
119→            if (node.prevSibling().isWhiteSpace() && node.removeSpacingBefore && !prevLeaf.isWhiteSpaceWithNewline()) {
120→                emit(node.startOffset, "Unexpected spacing before \":\"", true)
121→                if (autoCorrect) {
122→                    node
123→                        .prevSibling()
124→                        ?.let { prevSibling ->
125→                            prevSibling.treeParent.removeChild(prevSibling)
126→                        }
127→                }
128→            }
129→            val missingSpacingBefore =
130→                !node.prevSibling().isWhiteSpace() &&
131→                    (
132→                        psiParent is KtClassOrObject || psiParent is KtConstructor<*> ||
133→                            psiParent is KtTypeConstraint || psiParent.parent is KtTypeParameterList
134→                        )
135→            val missingSpacingAfter = !node.nextSibling().isWhiteSpace()
136→            when {
137→                missingSpacingBefore && missingSpacingAfter -> {
138→                    emit(node.startOffset, "Missing spacing around \":\"", true)
139→                    if (autoCorrect) {
140→                        node.upsertWhitespaceBeforeMe(" ")
141→                        node.upsertWhitespaceAfterMe(" ")
142→                    }
143→                }
144→                missingSpacingBefore -> {
145→                    emit(node.startOffset, "Missing spacing before \":\"", true)
146→                    if (autoCorrect) {
147→                        node.upsertWhitespaceBeforeMe(" ")
148→                    }
149→                }
150→                missingSpacingAfter -> {
151→                    emit(node.startOffset + 1, "Missing spacing after \":\"", true)
152→                    if (autoCorrect) {
153→                        node.upsertWhitespaceAfterMe(" ")
154→                    }
155→                }
156→            }
157→        }
158→    }
159→
160→    private inline val ASTNode.removeSpacingBefore: Boolean
161→        get() =
162→            psi
163→                .parent
164→                .let { psiParent ->
165→                    psiParent !is KtClassOrObject &&
166→                        psiParent !is KtConstructor<*> && // constructor : this/super
167→                        psiParent !is KtTypeConstraint && // where T : S
168→                        psiParent?.parent !is KtTypeParameterList
169→                }
170→}
171→
